mapper.select:
SELECT ca.*, u.username AS user_name, c.name AS coach_name
FROM coach_appointment ca
LEFT JOIN user u ON ca.user_id = u.id
LEFT JOIN coach c ON ca.coach_id = c.id
WHERE 1=1

    AND ca.coach_id = #{coachId}


    AND ca.user_id = #{userId}


    AND ca.status = #{status}


    AND ca.appointment_time >= #{startDate}


    AND ca.appointment_time <= #{endDate}


    AND u.username LIKE CONCAT('%', #{userName}, '%')

ORDER BY ca.create_time DESC
